import { HttpClient, HttpHeaders, HttpParams } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { BehaviorSubject, Observable, finalize } from 'rxjs';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class ApiHttpService {
  private http = inject(HttpClient);

  readonly AppUrl: string = environment.apiUrl;
  readonly MaxUploadSize = 20480; // 20 MB => 1024 KB = 1 MB

  private loadingCount = 0;
  private loadingEmitScheduled = false;
  readonly loading$ = new BehaviorSubject<boolean>(false);

  private scheduleLoadingEmit(): void {
    if (this.loadingEmitScheduled) {
      return;
    }

    this.loadingEmitScheduled = true;
    Promise.resolve().then(() => {
      this.loadingEmitScheduled = false;
      this.loading$.next(this.loadingCount > 0);
    });
  }

  private setLoading(on: boolean): void {
    this.loadingCount += on ? 1 : -1;
    if (this.loadingCount < 0) {
      this.loadingCount = 0;
    }
    this.scheduleLoadingEmit();
  }

  private withLoading<T>(obs: Observable<T>): Observable<T> {
    this.setLoading(true);
    return obs.pipe(finalize(() => this.setLoading(false)));
  }

  ladeHeaders(filesVorhanden: boolean, bearerToken?: string): HttpHeaders {
    let headers = new HttpHeaders();

    if (bearerToken) {
      headers = headers.set('Authorization', `Bearer ${bearerToken}`);
    }

    if (!filesVorhanden) {
      headers = headers.set('Content-Type', 'application/json; charset=utf-8');
    }

    return headers;
  }

  get<T = unknown>(modul: string, param?: Record<string, unknown>, afterSlash?: boolean): Observable<T> {
    const headers = this.ladeHeaders(false);
    const params = this.buildQueryParams(param);
    const hasParams = params.keys().length > 0;

    let url = `${this.AppUrl}${modul}`;
    if (!hasParams) {
      url += '/';
    } else {
      if (afterSlash === true) {
        url += '/';
      }
    }

    return this.withLoading(this.http.get<T>(url, { headers, params }));
  }

  getURL<T = unknown>(url: string): Observable<T> {
    return this.withLoading(this.http.get<T>(url));
  }

  post<T = unknown>(modul: string, daten: any, _filesVorhanden?: boolean): Observable<T> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD);
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.post<T>(url, daten, { headers }));
  }

  patch<T = unknown>(modul: string, id: any, daten: any, _filesVorhanden?: boolean): Observable<T> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD);

    const url = id !== ''
      ? `${this.AppUrl}${modul}/${id}/`
      : `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.patch<T>(url, daten, { headers }));
  }

  delete<T = unknown>(modul: string, id: any): Observable<T> {
    const headers = this.ladeHeaders(false);
    const url = `${this.AppUrl}${modul}/${id}/`;

    return this.withLoading(this.http.delete<T>(url, { headers }));
  }

  postBlob(modul: string, daten: any): Observable<Blob> {
    const isFD = typeof FormData !== 'undefined' && daten instanceof FormData;
    const headers = this.ladeHeaders(isFD).set('Accept', 'application/pdf');
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.post(url, daten, {
      headers,
      responseType: 'blob',
    }));
  }

  getWithBearer<T = unknown>(modul: string, token: string): Observable<T> {
    const headers = this.ladeHeaders(false, token);
    const url = `${this.AppUrl}${modul}/`;

    return this.withLoading(this.http.get<T>(url, { headers }));
  }

  cleanupOrphanMedia(payload: {
    target?: 'all' | 'news' | 'homepage' | 'inventar' | 'einsatzberichte' | 'anwesenheitsliste';
    delete?: boolean;
    allow_missing_db?: boolean;
  }): Observable<unknown> {
    return this.post('files/cleanup-orphans', payload, false);
  }

  private buildQueryParams(param?: Record<string, unknown>): HttpParams {
    if (!param || typeof param !== 'object') {
      return new HttpParams();
    }

    let params = new HttpParams();

    for (const [key, value] of Object.entries(param)) {
      params = this.appendParam(params, key, value);
    }

    return params;
  }

  private appendParam(params: HttpParams, key: string, value: unknown): HttpParams {
    if (value === undefined || value === null) {
      return params;
    }

    if (Array.isArray(value)) {
      let updated = params;
      value.forEach((entry) => {
        updated = this.appendParam(updated, key, entry);
      });
      return updated;
    }

    if (value instanceof Date) {
      return params.append(key, value.toISOString());
    }

    if (typeof value === 'object') {
      return params.append(key, JSON.stringify(value));
    }

    return params.append(key, String(value));
  }
}

import { Injectable, inject } from '@angular/core';
import { Router } from '@angular/router';
import { ApiHttpService } from './api-http.service';
import { UiMessageService } from './ui-message.service';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class AuthSessionService {
  private api = inject(ApiHttpService);
  private router = inject(Router);
  private messages = inject(UiMessageService);
  private readonly knownCookieNames = new Set([
    'app-access-token',
    'app-refresh-token',
    'csrftoken',
    'sessionid',
  ]);

  abmelden(): void {
    this.api.post('auth/logout', null, false).subscribe({
      next: () => {
        this.clearSessionAndCookies();
        this.router.navigate(['/login']);
      },
      error: (error: any) => {
        this.errorAnzeigen(error);
      },
    });
  }

  errorAnzeigen(response: any): void {
    const errorObject = response?.error;

    if (errorObject && typeof errorObject === 'object') {
      const msg = Object.values(errorObject)
        .map((value) => String(value))
        .join('\n');

      if (msg !== '') {
        this.messages.erstelleMessage('error', msg);
      }
    }

    if (response?.status === 401) {
      this.clearSessionAndCookies();
      this.router.navigate(['/login']);
    }
  }

  private clearSessionAndCookies(): void {
    this.clearSessionState();
    this.clearKnownCookies();
  }

  private clearSessionState(): void {
    if (typeof sessionStorage === 'undefined') {
      return;
    }

    ['PageNumber', 'Benutzername', 'public_token_global', 'auth_guard_ok_until', 'sw-cleanup-reloaded']
      .forEach((key) => sessionStorage.removeItem(key));

    for (let i = sessionStorage.length - 1; i >= 0; i--) {
      const key = sessionStorage.key(i);
      if (key && /^Page\d+$/.test(key)) {
        sessionStorage.removeItem(key);
      }
    }
  }

  private clearKnownCookies(): void {
    if (typeof document === 'undefined') {
      return;
    }

    let refreshPath = '/auth/token/refresh/';
    try {
      const base = typeof window !== 'undefined' ? window.location.origin : 'http://localhost';
      const apiPath = new URL(String(environment.apiUrl || '/api/v1/'), base).pathname.replace(/\/+$/g, '');
      refreshPath = `${apiPath}/auth/token/refresh/`;
    } catch {
      refreshPath = '/auth/token/refresh/';
    }

    document.cookie
      .split(';')
      .map((entry) => entry.trim())
      .forEach((cookie) => {
        const [name] = cookie.split('=');
        if (!this.knownCookieNames.has(name)) {
          return;
        }

        document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; SameSite=Lax`;
        document.cookie = `${name}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=${refreshPath}; SameSite=Lax`;
      });
  }
}

import { Injectable } from '@angular/core';
import { AbstractControl } from '@angular/forms';

@Injectable({
  providedIn: 'root',
})
export class CollectionUtilsService {
  arraySortByKey(array: any[], key: any): any[] {
    array.sort((a: any, b: any) => (a[key] === b[key] ? 0 : +(a[key] > b[key]) || -1));
    return array;
  }

  arraySortByKeyDesc(array: any[], key: any): any[] {
    array.sort((a: any, b: any) => (a[key] === b[key] ? 0 : +(a[key] < b[key]) || -1));
    return array;
  }

  sucheArrayInArray(gesamtArray: any[], teilArray: any[], vergleichKey: string): any[] {
    const arrayNeu = [];
    for (let i = 0; i < gesamtArray.length; i += 1) {
      let count = 0;
      for (let x = 0; x < teilArray.length; x += 1) {
        if (gesamtArray[i][vergleichKey] === teilArray[x][vergleichKey]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(gesamtArray[i]);
      }
    }
    return arrayNeu;
  }

  sucheNumberArrayInObjectArray(gesamtArray: any[], teilArray: any[], gesamtArrayKey: string): any[] {
    const arrayNeu = [];
    for (let i = 0; i < gesamtArray.length; i += 1) {
      let count = 0;
      for (let x = 0; x < teilArray.length; x += 1) {
        if (gesamtArray[i][gesamtArrayKey] === teilArray[x]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(gesamtArray[i]);
      }
    }
    return arrayNeu;
  }

  vergleicheZweiArrays(array1: any[], array2: any[], vergleichKey: string): any[] {
    const arrayNeu = array1;
    for (let i = 0; i < array2.length; i += 1) {
      let count = 0;
      for (let x = 0; x < arrayNeu.length; x += 1) {
        if (array2[i][vergleichKey] === arrayNeu[x][vergleichKey]) {
          count += 1;
        }
      }
      if (count === 0) {
        arrayNeu.push(array2[i]);
      }
    }
    return arrayNeu;
  }

  addItemFromSelectToList(control: AbstractControl, arrayGesamt: any[], array: any[]): void {
    const selectedId = control.value;
    if (selectedId !== '0') {
      if (array.length > 0) {
        let count = 0;
        for (let i = 0; i < array.length; i += 1) {
          if (selectedId === array[i]) {
            count += 1;
          }
        }
        if (count === 0) {
          for (let i = 0; i < arrayGesamt.length; i += 1) {
            if (selectedId === arrayGesamt[i].pkid) {
              array.push({
                pkid: arrayGesamt[i].pkid,
                kuerzel: arrayGesamt[i].kuerzel,
                name: arrayGesamt[i].name,
              });
              arrayGesamt.splice(i, 1);
            }
          }
        }
      } else {
        for (let i = 0; i < arrayGesamt.length; i += 1) {
          if (selectedId === arrayGesamt[i].pkid) {
            array.push({
              pkid: arrayGesamt[i].pkid,
              kuerzel: arrayGesamt[i].kuerzel,
              name: arrayGesamt[i].name,
            });
            arrayGesamt.splice(i, 1);
          }
        }
      }

      control.setValue(0, { onlySelf: true });
      this.arraySortByKey(array, 'kuerzel');
    }
  }

  addItemFromListToSelect(pkid: string, arrayGesamt: any[], array: any[]): void {
    for (let i = 0; i < array.length; i += 1) {
      if (pkid === array[i].pkid) {
        arrayGesamt.push({ pkid: array[i].pkid, kuerzel: array[i].kuerzel, name: array[i].name });
        array.splice(i, 1);
      }
    }
    this.arraySortByKey(arrayGesamt, 'kuerzel');
  }

  addFeldInArray(arrayGesamt: any[], array: any[], feldName: string, joinKey: string): any[] {
    const map = new Map(arrayGesamt.map((item) => [item[joinKey], item[feldName]]));

    return array.map((item) => {
      const key = item[joinKey];
      if (map.has(key)) {
        return { ...item, [feldName]: map.get(key) };
      }
      return item;
    });
  }

  addAllFieldsToNumberArray(arrayGesamt: any[], array: any[]): any[] {
    const dataNew = [];
    for (let i = 0; i < array.length; i += 1) {
      const pkid = array[i];
      for (let x = 0; x < arrayGesamt.length; x += 1) {
        if (pkid === arrayGesamt[x].pkid) {
          dataNew.push(arrayGesamt[x]);
        }
      }
    }

    return dataNew;
  }
}

import { Injectable } from '@angular/core';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class NavigationService {
  readonly Author = 'Ing. M. Reichenauer';

  ladeBreadcrumb(): any[] {
    const list: any[] = [];
    const pageNumber = Number.parseInt(sessionStorage.getItem('PageNumber') ?? '0', 10);

    const page1 = sessionStorage.getItem('Page1') ?? '';
    const page2 = sessionStorage.getItem('Page2') ?? '';
    const page3 = sessionStorage.getItem('Page3') ?? '';

    if (pageNumber === 1) {
      list.push(this.erstelleBreadcrumbLink(page1, true));
      sessionStorage.setItem('Page2', '');
      sessionStorage.setItem('Page3', '');
    } else if (pageNumber >= 1) {
      list.push(this.erstelleBreadcrumbLink(page1, false));
    }

    if (pageNumber === 2) {
      list.push(this.erstelleBreadcrumbLink(page2, true));
      sessionStorage.setItem('Page3', '');
    } else if (pageNumber >= 2) {
      list.push(this.erstelleBreadcrumbLink(page2, false));
    }

    if (pageNumber === 3) {
      list.push(this.erstelleBreadcrumbLink(page3, true));
    }

    for (let i = 0; i < list.length; i += 1) {
      list[i].number = i + 1;
    }

    return list;
  }

  erstelleBreadcrumbLink(pagename: string, active: boolean): any {
    let link = '';
    const page = String(pagename ?? '').replace(' ', '');
    let kuerzel = '';

    if (page.toLowerCase() === 'start') {
      link = '/start';
      kuerzel = 'Start';
    } else if (page === 'FMD') {
      link = '/fmd';
      kuerzel = 'FMD';
    } else if (page === 'ATM') {
      link = '/atemschutz';
      kuerzel = 'Atemschutz';
    } else if (page === 'ATM_M') {
      link = '/atemschutz/masken';
      kuerzel = 'Masken';
    } else if (page === 'ATM_G') {
      link = '/atemschutz/geraete';
      kuerzel = 'Geräte';
    } else if (page === 'ATM_MG') {
      link = '/atemschutz/messgeraete';
      kuerzel = 'Messgeräte';
    } else if (page === 'ATM_DB') {
      link = '/atemschutz/dienstbuch';
      kuerzel = 'Dienstbuch';
    } else if (page === 'NEWS') {
      link = '/news';
      kuerzel = 'News';
    } else if (page === 'HOME') {
      link = '/homepage';
      kuerzel = 'Homepage';
    } else if (page === 'FZ') {
      link = '/fahrzeuge';
      kuerzel = 'Fahrzeug Beladung';
    } else if (page === 'INV') {
      link = '/inventar';
      kuerzel = 'Inventar';
    } else if (page === 'WS') {
      link = '/wartung-service';
      kuerzel = 'Wartung/Service';
    } else if (page === 'BER') {
      link = '/einsatzbericht';
      kuerzel = 'Einsatzbericht';
    } else if (page === 'ANW') {
      link = '/anwesenheitsliste';
      kuerzel = 'Anwesenheitsliste';
    } else if (page === 'PDF') {
      link = '/pdf_template';
      kuerzel = 'PDF Templates';
    } else if (page === 'VER') {
      link = '/verwaltung';
      kuerzel = 'Verwaltung';
    } else if (page === 'V_M') {
      link = '/mitglied';
      kuerzel = 'Mitglieder';
    } else if (page === 'JUGEND') {
      link = '/jugend';
      kuerzel = 'Jugend';
    } else if (page === 'V_MK') {
      link = '/modul_konfiguration';
      kuerzel = 'Modul Konfiguration';
    } else if (page === 'V_B') {
      link = '/benutzer';
      kuerzel = 'Benutzer';
    } else if (page === 'V_KO') {
      link = '/konfiguration';
      kuerzel = 'Konfiguration';
    } else if (page === 'V_ED') {
      link = '/eigene_daten';
      kuerzel = 'Eigene Daten';
    }

    return {
      name: pagename,
      link,
      number: 0,
      kuerzel,
      active,
    };
  }

  setzeNeueBreadcrumbDaten(pageNeu: string, pageNumber: number): void {
    const pageNumberBack = pageNumber - 1;
    const pageNumberForward = pageNumber + 1;
    const pageBack = sessionStorage.getItem(`Page${pageNumberBack}`) ?? '';
    const page = sessionStorage.getItem(`Page${pageNumber}`) ?? '';

    if (pageNeu === pageBack) {
      sessionStorage.setItem('PageNumber', pageNumberBack.toString());
      sessionStorage.setItem(`Page${pageNumberBack}`, pageNeu);
      return;
    }

    if (pageNeu === page) {
      sessionStorage.setItem('PageNumber', pageNumber.toString());
      sessionStorage.setItem(`Page${pageNumber}`, pageNeu);
      return;
    }

    if (pageNumberForward <= 6) {
      sessionStorage.setItem('PageNumber', pageNumberForward.toString());
      sessionStorage.setItem(`Page${pageNumberForward}`, pageNeu);
    }
  }

  ladeFooter(): string {
    const year = new Date().getFullYear();
    const footer = `Version ${environment.version}\n${String.fromCharCode(169)} ${year} by ${this.Author}`;
    return footer;
  }
}

﻿import { Component, OnInit, inject } from '@angular/core';
import { ApiHttpService } from 'src/app/_service/api-http.service';
import { AuthSessionService } from 'src/app/_service/auth-session.service';
import { CollectionUtilsService } from 'src/app/_service/collection-utils.service';
import { NavigationService } from 'src/app/_service/navigation.service';
import { UiMessageService } from 'src/app/_service/ui-message.service';
import {
  ImrButtonComponent,
  ImrFormFieldComponent,
  ImrHeaderComponent,
  ImrPageLayoutComponent,
  ImrSectionCardComponent,
  ImrTopActionsComponent,
  UiControlErrorsDirective,
} from '../../imr-ui-library';
import { MatTabsModule } from '@angular/material/tabs';
import { AbstractControl, FormControl, FormGroup, FormsModule, ReactiveFormsModule, ValidatorFn, Validators } from '@angular/forms';
import { MatError } from '@angular/material/form-field';
import { MatInput } from '@angular/material/input';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MatSortModule } from '@angular/material/sort';
import { MatPaginatorModule } from '@angular/material/paginator';
import { IAtemschutzGeraet } from 'src/app/_interface/atemschutz_geraet';
import { MatIcon } from '@angular/material/icon';
import { MatOption, MatSelect } from '@angular/material/select';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { IAtemschutzGeraetProtokoll } from 'src/app/_interface/atemschutz_geraet_protokoll';
import { IMitglied } from 'src/app/_interface/mitglied';
import { DateInputMaskDirective } from '../../_directive/date-input-mask.directive';

@Component({
  selector: 'app--atemschutzgeraete',
  imports: [
    ImrButtonComponent,
    ImrHeaderComponent,
    ImrPageLayoutComponent,
    ImrSectionCardComponent,
    ImrTopActionsComponent,
    MatTabsModule,
    FormsModule,
    ReactiveFormsModule,
    ImrFormFieldComponent,
    UiControlErrorsDirective,
    MatSelect,
    MatOption,
    MatInput,
    MatError,
    MatTableModule,
    MatSortModule,
    MatPaginatorModule,
    MatIcon,
    MatCheckboxModule,
    DateInputMaskDirective,
  ],
  templateUrl: './atemschutz-geraete.component.html',
  styleUrl: './atemschutz-geraete.component.sass'
})
export class AtemschutzGeraeteComponent implements OnInit {
  private apiHttpService = inject(ApiHttpService);
  private authSessionService = inject(AuthSessionService);
  private collectionUtilsService = inject(CollectionUtilsService);
  private navigationService = inject(NavigationService);
  private uiMessageService = inject(UiMessageService);
  title = "Geräte verwalten";
  title_modul = this.title;
  title_pruefung = "Geräte prüfen";
  modul = "atemschutz/geraete";
  showPruefungForm: boolean = false;
  showPruefungTable: boolean = false;

  geraete: IAtemschutzGeraet[] = [];
  pruefungen: IAtemschutzGeraetProtokoll[] = [];
  mitglieder: IMitglied[] = [];
  userRoles: string[] = [];
  canEditProtocol = false;
  rolesResolved = false;
  breadcrumb: any = [];
  dataSource = new MatTableDataSource<IAtemschutzGeraet>(this.geraete);
  dataSourcePruefungen = new MatTableDataSource<IAtemschutzGeraetProtokoll>(this.pruefungen);
  sichtbareSpalten: string[] = ['inv_nr', 'typ', 'art', 'standort', 'letzte_pruefung', 'naechste_pruefung', 'actions'];
  sichtbareSpaltenPruefungen: string[] = ['datum', 'taetigkeit', 'name_pruefer', 'actions'];

  formModul = new FormGroup({
    id: new FormControl(''),
    inv_nr: new FormControl('', Validators.required),
    art: new FormControl(''),
    typ: new FormControl(''),
    druckminderer: new FormControl(''),
    lungenautomat: new FormControl(''),
    rahmen_nr: new FormControl(''),
    eigentuemer: new FormControl(''),
    barcode: new FormControl(''),
    standort: new FormControl(''),
    baujahr: new FormControl(''),
    datum_im_dienst: new FormControl(''),
    naechste_gue: new FormControl('')
  });

  formPruefung = new FormGroup({
    id: new FormControl(''),
    geraet_id: new FormControl(0, Validators.required),
    datum: new FormControl('', [
      Validators.pattern(/^([0-3]\d)\.([0-1]\d)\.(\d{4})$/),
      this.validDateDDMMYYYY(),
      Validators.required
    ]),
    taetigkeit: new FormControl(''),
    verwendung_typ: new FormControl(''),
    verwendung_min: new FormControl(0),
    mitglied_id: new FormControl(0),
    geraet_ok: new FormControl(false),
    name_pruefer: new FormControl('', Validators.required),
    tausch_gleitring: new FormControl(false),
    tausch_hochdruckdichtring: new FormControl(false),
    tausch_membran: new FormControl(false),
    pruefung_10jahre: new FormControl(false),
    pruefung_jaehrlich: new FormControl(false),
    preufung_monatlich: new FormControl(false),
    notiz: new FormControl(''),
  });

  ngOnInit(): void {
    sessionStorage.setItem("PageNumber", "3");
    sessionStorage.setItem("Page3", "ATM_G");
    this.breadcrumb = this.navigationService.ladeBreadcrumb();
    this.formModul.disable();
    this.formPruefung.disable();
    this.loadCurrentUserRoles();

    this.reloadGeraeteKontext();
  }

  private reloadGeraeteKontext(): void {
    this.apiHttpService.get(this.modul).subscribe({
      next: (erg: any) => {
        try {
          this.geraete = erg.main as any[];
          this.dataSource.data = erg.main as any[];

          const fmd = erg.fmd as any[];
          const mitgliederGesamt= erg.mitglieder as any[];
          const memberMap = new Map<number, any>(mitgliederGesamt.map((m: any) => [m.pkid, m]));

          this.mitglieder = fmd.map(item => {
            const mitg = memberMap.get(item.mitglied_id) || {};
            return {
              ...item,
              stbnr: mitg.stbnr,
              vorname: mitg.vorname,
              nachname: mitg.nachname,
              geburtsdatum: mitg.geburtsdatum,
              hauptberuflich: mitg.hauptberuflich
            };
          });
          this.mitglieder = this.collectionUtilsService.arraySortByKey(this.mitglieder, 'stbnr');
        } catch (e: any) {
